import React, { useCallback, useEffect, useMemo, useState } from 'react'
import { showToast } from '../../utils/toast'
import { useAuth } from '../../context/AuthContext'
import { taskService, productService } from '../../services/api'
import '../../styles/technician/technician-tasks.css'

const STATUS_OPTIONS = [
  { value: 'ALL', label: 'Tất cả trạng thái công việc' },
  { value: 'PENDING', label: 'Chờ xử lý' },
  { value: 'IN_PROGRESS', label: 'Đang thực hiện' },
  { value: 'COMPLETED', label: 'Hoàn thành' },
  { value: 'CANCELLED', label: 'Đã hủy' },
  { value: 'OVERDUE', label: 'Quá hạn' },
]

const TASK_TYPE_OPTIONS = [
  { value: '1', label: 'Xử lý ao (POND_PROCESS)' },
  { value: '2', label: 'Cho ăn (FEEDING)' },
  { value: '3', label: 'Cho thuốc (TREATMENT)' },
  { value: '4', label: 'Kiểm tra môi trường (ENVIRONMENTAL_CHECK)' },
  { value: '5', label: 'Thu hoạch (HARVEST)' },
  { value: '6', label: 'Công việc khác (OTHER)' },
]

const normalize = (v) => String(v || '').trim().toUpperCase()
const formatDate = (v) => (v ? new Date(v).toLocaleString('vi-VN') : '-')

const initialForm = {
  task_type: '1',
  task_title: '',
  description: '',
  start_date: '',
  due_date: '',
  product_id: '',
  quantity: '',
  assignments: [], // [{pond_id, worker_id}]
}

function TechnicianTasks() {
  const { user } = useAuth()
  const [tasks, setTasks] = useState([])
  const [matrixPonds, setMatrixPonds] = useState([])
  const [matrixWorkers, setMatrixWorkers] = useState([])
  const [products, setProducts] = useState([])
  const [loading, setLoading] = useState(false)

  // Filter states
  const [filterStatus, setFilterStatus] = useState('ALL')
  const [filterType, setFilterType] = useState('ALL')
  const [searchTerm, setSearchTerm] = useState('')

  // Modal states
  const [isCreateOpen, setIsCreateOpen] = useState(false)
  const [selectedTask, setSelectedTask] = useState(null)

  // Form state
  const [form, setForm] = useState(initialForm)

  // 1. Fetch main task list
  const fetchTasks = useCallback(async () => {
    try {
      const res = await taskService.getAllTasks()
      if (res.data?.success) {
        setTasks(res.data.data)
      }
    } catch (err) {
      console.error(err)
      showToast({ title: 'Không thể tải danh sách công việc', type: 'error' })
    }
  }, [])

  // 2. Fetch ponds available for matrix (ĐÃ ĐỒNG BỘ THÊM PARAMS TYPE_ID)
  const fetchPondsForMatrix = useCallback(async (typeId) => {
    if (!typeId) return
    try {
      const res = await taskService.getPondsForTask({ params: { type_id: parseInt(typeId, 10) } })
      if (res.data?.success) {
        setMatrixPonds(res.data.data)
      }
    } catch (err) {
      console.error(err)
    }
  }, [])

  // 3. Fetch workers available for matrix
  const fetchWorkersForMatrix = useCallback(async () => {
    try {
      const res = await taskService.getWorkersForTask()
      if (res.data?.success) {
        setMatrixWorkers(res.data.data)
      }
    } catch (err) {
      console.error(err)
    }
  }, [])

  // 4. Fetch available products
  const fetchProducts = useCallback(async () => {
    try {
      const res = await productService.getAllProducts()
      if (res.data?.success) {
        setProducts(res.data.data)
      }
    } catch (err) {
      console.error(err)
    }
  }, [])

  // TỰ ĐỘNG LÀM MỚI DANH SÁCH AO KHI THAY ĐỔI LOẠI CÔNG VIỆC TRÊN DROPDOWN
  useEffect(() => {
    if (isCreateOpen && form.task_type) {
      fetchPondsForMatrix(form.task_type)
      setForm(prev => ({ ...prev, assignments: [] })) // Reset các ô tích cũ để tránh lệch ao
    }
  }, [form.task_type, isCreateOpen, fetchPondsForMatrix])

  // Initial load
  useEffect(() => {
    fetchTasks()
    fetchWorkersForMatrix()
    fetchProducts()
  }, [fetchTasks, fetchWorkersForMatrix, fetchProducts])

  // Determine if inventory material section is required based on task type
  const isProductRequired = useMemo(() => {
    const currentType = parseInt(form.task_type, 10)
    return [1, 2, 3].includes(currentType) // POND_PROCESS (1), FEEDING (2), TREATMENT (3)
  }, [form.task_type])

  // Computed statistics summary values
  const stats = useMemo(() => {
    const res = { total: 0, pending: 0, progress: 0, completed: 0, overdue: 0 }
    tasks.forEach((t) => {
      res.total++
      const s = normalize(t.status)
      if (s === 'PENDING') res.pending++
      else if (s === 'IN_PROGRESS') res.progress++
      else if (s === 'COMPLETED') res.completed++
      else if (s === 'OVERDUE') res.overdue++
    })
    return res
  }, [tasks])

  // Filtered task results mapping
  const filteredTasks = useMemo(() => {
    return tasks.filter((t) => {
      const matchStatus = filterStatus === 'ALL' || normalize(t.status) === normalize(filterStatus)
      const matchType = filterType === 'ALL' || String(t.type_id) === String(filterType)
      
      const searchStr = `${t.task_code || ''} ${t.task_title || ''} ${t.pond_name || ''} ${t.pond_code || ''}`.toLowerCase()
      const matchSearch = !searchTerm.trim() || searchStr.includes(searchTerm.toLowerCase())
      
      return matchStatus && matchType && matchSearch
    })
  }, [tasks, filterStatus, filterType, searchTerm])

  const handleCellClick = (pondId, workerId) => {
    const exists = form.assignments.find((a) => a.pond_id === pondId && a.worker_id === workerId)
    let updated = []
    if (exists) {
      updated = form.assignments.filter((a) => !(a.pond_id === pondId && a.worker_id === workerId))
    } else {
      updated = [...form.assignments, { pond_id: pondId, worker_id: workerId }]
    }
    setForm({ ...form, assignments: updated })
  }

  const handleCreateTask = async () => {
    if (!form.assignments || form.assignments.length === 0) {
      showToast({ title: 'Vui lòng chọn ít nhất một phân công trong ma trận', type: 'warning' })
      return
    }
    if (!form.description?.trim()) {
      showToast({ title: 'Vui lòng nhập hướng dẫn kỹ thuật chi tiết', type: 'warning' })
      return
    }

    const confirmAction = window.confirm(`Xác nhận tạo ${form.assignments.length} nhiệm vụ kỹ thuật riêng biệt?`)
    if (!confirmAction) return

    setLoading(true)
    try {
      let finalTitle = form.task_title?.trim()
      if (!finalTitle) {
        const typeOpt = TASK_TYPE_OPTIONS.find((o) => o.value === form.task_type)
        finalTitle = typeOpt ? `Công tác ${typeOpt.label.split(' (')[0]}` : 'Công việc kỹ thuật'
      }

      const numericTypeId = parseInt(form.task_type, 10)

      for (const assignment of form.assignments) {
        const selectedPondObj = matrixPonds.find((p) => Number(p.pond_id) === Number(assignment.pond_id))

        const singleTaskData = {
          type_id: numericTypeId,
          pond_id: Number(assignment.pond_id),
          task_title: finalTitle,
          description: form.description.trim(),
          start_date: form.start_date || new Date().toISOString(),
          due_date: form.due_date,
          assigned_workers: [Number(assignment.worker_id)],
        }

        if (selectedPondObj?.season_id) {
          singleTaskData.season_id = Number(selectedPondObj.season_id)
        }

        if (isProductRequired && form.product_id) {
          singleTaskData.product_id = Number(form.product_id)
          singleTaskData.quantity = parseFloat(form.quantity) || 0
        }

        await taskService.createTask(singleTaskData)
      }

      showToast({ title: `Kích hoạt thành công ${form.assignments.length} công việc!`, type: 'success' })
      setForm(initialForm)
      setIsCreateOpen(false)
      await fetchTasks()
    } catch (err) {
      const errorMsg = err.response?.data?.error || err.response?.data?.message || 'Lỗi hệ thống'
      showToast({ title: 'Không thể xử lý: ' + errorMsg, type: 'error' })
    } finally {
      setLoading(false)
    }
  }

  const handleCancelTask = async (taskId) => {
    if (!window.confirm('Bạn có chắc chắn muốn hủy hoàn toàn công việc này?')) return
    try {
      const res = await taskService.cancelTask(taskId)
      if (res.data?.success) {
        showToast({ title: 'Đã hủy công việc thành công', type: 'success' })
        if (selectedTask) setSelectedTask(null)
        await fetchTasks()
      }
    } catch (err) {
      showToast({ title: 'Lỗi hủy công việc', type: 'error' })
    }
  }

  const getComputedStatus = (task) => {
    const status = normalize(task.status)
    if (status === 'COMPLETED' || status === 'CANCELLED') return status
    if (task.due_date && new Date(task.due_date) < new Date()) return 'OVERDUE'
    return status
  }

  const getStatusLabel = (status) => {
    const found = STATUS_OPTIONS.find((o) => normalize(o.value) === normalize(status))
    return found ? found.label : status
  }

  const getStatusBadgeClass = (task) => {
    const status = getComputedStatus(task)
    switch (status) {
      case 'PENDING': return 'task-status task-status--pending'
      case 'IN_PROGRESS': return 'task-status task-status--progress'
      case 'COMPLETED': return 'task-status task-status--done'
      case 'CANCELLED': return 'task-status task-status--cancelled'
      case 'OVERDUE': return 'task-status task-status--overdue'
      default: return 'task-status'
    }
  }

  return (
    <div className="technician-tasks">
      
      {/* 1. TOP OVERVIEW METRICS */}
      <div className="admin-users_stats-grid">
        <div className="admin-users_stat-card">
          <span className="admin-users_stat-label">Tổng công việc</span>
          <strong className="admin-users_stat-value">{stats.total}</strong>
        </div>
        <div className="admin-users_stat-card">
          <span className="admin-users_stat-label">Chờ xử lý</span>
          <strong className="admin-users_stat-value" style={{ color: '#f59e0b' }}>{stats.pending}</strong>
        </div>
        <div className="admin-users_stat-card">
          <span className="admin-users_stat-label">Đang thực hiện</span>
          <strong className="admin-users_stat-value" style={{ color: '#3b82f6' }}>{stats.progress}</strong>
        </div>
        <div className="admin-users_stat-card">
          <span className="admin-users_stat-label">Hoàn thành</span>
          <strong className="admin-users_stat-value" style={{ color: '#10b981' }}>{stats.completed}</strong>
        </div>
        <div className="admin-users_stat-card">
          <span className="admin-users_stat-label">Quá hạn</span>
          <strong className="admin-users_stat-value" style={{ color: '#ef4444' }}>{stats.overdue}</strong>
        </div>
      </div>

      {/* 2. FILTER ACTION ROW CONTROL */}
      <div className="admin-users_filter-card">
        <div className="admin-users_search-box">
          <input
            type="text"
            className="form-input-text-base"
            placeholder="Tìm theo mã việc, tiêu đề hoặc thông tin ao..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>
        <div className="admin-users_filter-groups">
          <select 
            className="form-input-text-base" 
            value={filterStatus} 
            onChange={(e) => setFilterStatus(e.target.value)}
          >
            {STATUS_OPTIONS.map(o => <option key={o.value} value={o.value}>{o.label}</option>)}
          </select>

          <select 
            className="form-input-text-base" 
            value={filterType} 
            onChange={(e) => setFilterType(e.target.value)}
          >
            <option value="ALL">Tất cả loại nghiệp vụ</option>
            {TASK_TYPE_OPTIONS.map(o => <option key={o.value} value={o.value}>{o.label.split(' (')[0]}</option>)}
          </select>

          <button type="button" className="btn btn-primary" onClick={() => { setForm(initialForm); setIsCreateOpen(true); }}>
            + Giao việc Ma Trận
          </button>
        </div>
      </div>

      {/* 3. MAIN DATA TABLE RENDERING */}
      <div className="admin-users_table-container">
        <table className="admin-users_table">
          <thead>
            <tr>
              <th>Mã công việc</th>
              <th>Ao nuôi</th>
              <th>Tiêu đề công việc</th>
              <th>Hạn hoàn thành</th>
              <th>Trạng thái</th>
              <th style={{ textAlign: 'center' }}>Thao tác</th>
            </tr>
          </thead>
          <tbody>
            {filteredTasks.length === 0 ? (
              <tr>
                <td colSpan="6" style={{ textAlign: 'center', color: '#94a3b8', padding: '24px' }}>
                  Không tìm thấy bản ghi công việc nào phù hợp với bộ lọc hiện tại.
                </td>
              </tr>
            ) : (
              filteredTasks.map((task) => (
                <tr key={task.task_id} className="admin-users_tr-row">
                  <td style={{ fontWeight: '600', color: '#0284c7' }}>{task.task_code || `ID: ${task.task_id}`}</td>
                  <td>
                    <div style={{ fontWeight: '500' }}>{task.pond_name}</div>
                    <div style={{ fontSize: '11px', color: '#64748b' }}>{task.pond_code}</div>
                  </td>
                  <td>
                    <div style={{ fontWeight: '500' }}>{task.task_title}</div>
                    <div className="task-row-desc">{task.type_name || 'Nghiệp vụ chung'}</div>
                  </td>
                  <td>{formatDate(task.due_date)}</td>
                  <td>
                    <span className={getStatusBadgeClass(task)}>
                      {getStatusLabel(getComputedStatus(task))}
                    </span>
                  </td>
                  <td style={{ textAlign: 'center' }}>
                    <button type="button" className="btn btn-secondary btn-sm" onClick={() => setSelectedTask(task)}>
                      Xem chi tiết
                    </button>
                  </td>
                </tr>
              ))
            )}
          </tbody>
        </table>
      </div>

      {/* 4. MODAL XEM CHI TIẾT CÔNG VIỆC CHUẨN GRID ĐỒNG BỘ 100% POND/SEASON */}
      {selectedTask && (
        <div className="modal" onClick={() => setSelectedTask(null)}>
          <div className="modal-content technician-seasons_modal" style={{ maxWidth: '800px' }} onClick={(e) => e.stopPropagation()}>
            <h3 className="technician-seasons_modal-title">Chi tiết tiến độ công việc</h3>

            <div className="technician-seasons_detail-grid">
              <div>
                <strong>Mã công việc (task_code):</strong>
                <p style={{ color: '#0284c7', fontWeight: '600' }}>{selectedTask.task_code || '-'}</p>
              </div>
              <div>
                <strong>Loại công việc (task_types):</strong>
                <p><strong>{selectedTask.type_name || selectedTask.task_type || '-'}</strong></p>
              </div>
              
              <div style={{ gridColumn: '1 / -1' }}>
                <strong>Tiêu đề công việc (task_title):</strong>
                <p style={{ fontWeight: '500', color: '#1e293b' }}>{selectedTask.task_title || '-'}</p>
              </div>

              <div>
                <strong>Ao nuôi thực hiện (pond_id):</strong>
                <p>{selectedTask.pond_name || '-'} {selectedTask.pond_code ? `(${selectedTask.pond_code})` : ''}</p>
              </div>
              <div>
                <strong>Thuộc mùa vụ (season_id):</strong>
                <p>{selectedTask.season_name || 'Công việc chung (Không gắn với mùa vụ)'}</p>
              </div>

              <div>
                <strong>Thời gian bắt đầu kế hoạch (start_date):</strong>
                <p>{formatDate(selectedTask.start_date)}</p>
              </div>
              <div>
                <strong>Hạn chót hoàn thành (due_date):</strong>
                <p>{formatDate(selectedTask.due_date)}</p>
              </div>

              <div>
                <strong>Kỹ sư giao việc (assigned_by):</strong>
                <p>{selectedTask.creator_name || `Kỹ sư hệ thống (ID: ${selectedTask.assigned_by})`}</p>
              </div>
              <div>
                <strong>Trạng thái công việc tổng (status):</strong>
                <p style={{ marginTop: '4px' }}>
                  <span className={getStatusBadgeClass(selectedTask)}>
                    {getStatusLabel(getComputedStatus(selectedTask))}
                  </span>
                </p>
              </div>

              <div>
                <strong>Ngày tạo bản ghi (created_at):</strong>
                <p style={{ color: '#64748b', fontSize: '0.85rem' }}>{formatDate(selectedTask.created_at)}</p>
              </div>
              <div>
                <strong>Cập nhật cuối lúc (updated_at):</strong>
                <p style={{ color: '#64748b', fontSize: '0.85rem' }}>{formatDate(selectedTask.updated_at)}</p>
              </div>

              {selectedTask.product_info ? (
                <div style={{ gridColumn: '1 / -1', background: '#f0f9ff', borderColor: '#bae6fd' }}>
                  <strong style={{ color: '#0369a1' }}>Vật tư chỉ định sử dụng (task_product_usage):</strong>
                  <p style={{ marginTop: '6px', color: '#1e293b' }}>
                    Sản phẩm: <strong style={{ color: '#0369a1' }}>{selectedTask.product_info.product_name}</strong> 
                    &nbsp;—&nbsp; Số lượng định mức (quantity): <strong style={{ color: '#0284c7', fontSize: '1.05rem' }}>{selectedTask.product_info.quantity}</strong> {selectedTask.product_info.unit || ''}
                  </p>
                </div>
              ) : (
                <div style={{ gridColumn: '1 / -1', background: '#f8fafc', borderStyle: 'dashed', color: '#64748b' }}>
                  <span style={{ fontSize: '0.85rem', fontStyle: 'italic' }}>Công việc này không yêu cầu xuất vật tư từ kho đi kèm.</span>
                </div>
              )}

              <div style={{ gridColumn: '1 / -1', background: '#fcf8f2', borderColor: '#fed7aa' }}>
                <strong style={{ color: '#c2410c' }}>Chi tiết phân công & Tiến độ thực tế của Công nhân (task_workers):</strong>
                <div style={{ marginTop: '8px', display: 'flex', flexDirection: 'column', gap: '8px' }}>
                  {selectedTask.assigned_workers_list && selectedTask.assigned_workers_list.length > 0 ? (
                    selectedTask.assigned_workers_list.map((worker, idx) => (
                      <div key={`detail-worker-${worker.worker_id || idx}`} style={{ background: '#ffffff', padding: '10px 14px', borderRadius: '8px', border: '1px solid #ffedd5' }}>
                        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                          <strong>Công nhân phụ trách: <span style={{ color: '#ea580c', fontSize: '0.95rem' }}>{worker.full_name}</span></strong>
                          <span style={{ 
                            fontSize: '11px', 
                            padding: '3px 10px', 
                            borderRadius: '20px', 
                            background: worker.worker_status === 'DONE' ? '#d1fae5' : '#fef3c7', 
                            color: worker.worker_status === 'DONE' ? '#065f46' : '#d97706', 
                            fontWeight: '600' 
                          }}>
                            {worker.worker_status || 'ASSIGNED'}
                          </span>
                        </div>
                        
                        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '8px', marginTop: '8px', fontSize: '0.85rem', color: '#475569' }}>
                          <div>⏱ Nhận việc thực tế (started_at): <span style={{ color: '#0f172a', fontWeight: '500' }}>{formatDate(worker.started_at)}</span></div>
                          <div>✓ Bấm xong thực tế (completed_at): <span style={{ color: '#0f172a', fontWeight: '500' }}>{formatDate(worker.completed_at)}</span></div>
                        </div>

                        {worker.note && (
                          <div style={{ marginTop: '8px', padding: '6px 10px', background: '#f8fafc', borderRadius: '6px', borderLeft: '3px solid #cbd5e1', fontSize: '0.85rem', color: '#334155' }}>
                            <strong>Báo cáo/Ghi chú từ công nhân (note):</strong> {worker.note}
                          </div>
                        )}
                      </div>
                    ))
                  ) : (
                    <p style={{ color: '#ef4444', fontStyle: 'italic', margin: 0, fontSize: '0.85rem' }}>Chưa cấu hình danh sách công nhân phụ trách.</p>
                  )}
                </div>
              </div>

              <div style={{ gridColumn: '1 / -1' }}>
                <strong>Hướng dẫn kỹ thuật / Mô tả nghiệp vụ (description):</strong>
                <p className="technical-instruction-text" style={{ whiteSpace: 'pre-line', color: '#334155', background: '#ffffff', padding: '12px', borderRadius: '8px', border: '1px solid #cbd5e1', marginTop: '6px', lineHeight: '1.5', fontSize: '0.9rem' }}>
                  {selectedTask.description || 'Không có mô tả hoặc hướng dẫn cụ thể.'}
                </p>
              </div>
            </div>

            {selectedTask.task_images && selectedTask.task_images.length > 0 && (
              <div style={{ marginTop: '16px', padding: '0 4px' }}>
                <span style={{ fontWeight: '600', fontSize: '0.85rem', color: '#475569' }}>Hình ảnh minh chứng thực địa (task_images):</span>
                <div style={{ display: 'flex', gap: '12px', marginTop: '8px', flexWrap: 'wrap' }}>
                  {selectedTask.task_images.map((imgUrl, i) => (
                    <img 
                      key={`task-img-view-${i}`} 
                      src={imgUrl} 
                      alt={`Báo cáo thực địa ${i + 1}`} 
                      style={{ width: '90px', height: '90px', objectFit: 'cover', borderRadius: '8px', border: '1px solid #cbd5e1', cursor: 'pointer', transition: 'transform 0.2s' }} 
                      onClick={() => window.open(imgUrl, '_blank')}
                      onMouseEnter={(e) => e.target.style.transform = 'scale(1.05)'}
                      onMouseLeave={(e) => e.target.style.transform = 'scale(1)'}
                    />
                  ))}
                </div>
              </div>
            )}

            <div className="technician-seasons_actions" style={{ marginTop: '24px', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
              <div>
                {normalize(selectedTask.status) === 'PENDING' && (
                  <button type="button" className="btn btn-danger" onClick={() => handleCancelTask(selectedTask.task_id)}>
                    Hủy bỏ công việc
                  </button>
                )}
              </div>
              <button type="button" className="btn btn-secondary" onClick={() => setSelectedTask(null)}>Đóng hộp thoại</button>
            </div>
          </div>
        </div>
      )}

      {/* 5. MODAL TẠO CÔNG VIỆC MA TRẬN PHÂN PHỐI */}
      {isCreateOpen && (
        <div className="modal" onClick={() => setIsCreateOpen(false)}>
          <div className="modal-content admin-users_modal" style={{ maxWidth: '900px' }} onClick={(e) => e.stopPropagation()}>
            <h3 className="admin-users_modal-title">Giao việc thông minh hệ Ma Trận</h3>
            
            <div className="admin-users_form-scroll-container" style={{ maxHeight: '65vh', overflowY: 'auto', paddingRight: '4px' }}>
              
              <div className="admin-users_detail-grid row-3-cols" style={{ marginBottom: '12px' }}>
                <div>
                  <label className="admin-users_detail-label">Mẫu nghiệp vụ chỉ định <span className="text-red">*</span></label>
                  <select
                    className="form-input-text-base"
                    value={form.task_type}
                    onChange={(e) => setForm({ ...form, task_type: e.target.value })}
                  >
                    {TASK_TYPE_OPTIONS.map(o => <option key={o.value} value={o.value}>{o.label}</option>)}
                  </select>
                </div>

                <div style={{ gridColumn: 'span 2' }}>
                  <label className="admin-users_detail-label">Tiêu đề công việc (Để trống sẽ tự sinh theo mẫu)</label>
                  <input
                    type="text"
                    className="form-input-text-base"
                    placeholder="Ví dụ: Kiểm tra định kỳ sàng ăn, Đánh vôi bạt ao..."
                    value={form.task_title}
                    onChange={(e) => setForm({ ...form, task_title: e.target.value })}
                  />
                </div>
              </div>

              {/* DYNAMIC INVENTORY SECTION BASED ON TYPE */}
              {isProductRequired && (
                <div className="admin-users_detail-grid" style={{ background: '#f0f9ff', padding: '12px', borderRadius: '8px', border: '1px solid #bae6fd', marginBottom: '12px' }}>
                  <div>
                    <label className="admin-users_detail-label" style={{ color: '#0369a1', fontWeight: '600' }}>Vật tư cấp phát từ kho</label>
                    <select
                      className="form-input-text-base"
                      value={form.product_id}
                      onChange={(e) => setForm({ ...form, product_id: e.target.value })}
                    >
                      <option value="">-- Chọn sản phẩm thức ăn/thuốc tiêu hao --</option>
                      {products.map(p => (
                        <option key={p.product_id} value={p.product_id}>
                          {p.product_name} (Tồn: {p.stock_quantity} {p.unit})
                        </option>
                      ))}
                    </select>
                  </div>
                  <div>
                    <label className="admin-users_detail-label" style={{ color: '#0369a1', fontWeight: '600' }}>Số lượng định mức chỉ định</label>
                    <input
                      type="number"
                      className="form-input-text-base"
                      placeholder="Nhập số lượng tiêu hao..."
                      value={form.quantity}
                      onChange={(e) => setForm({ ...form, quantity: e.target.value })}
                    />
                  </div>
                </div>
              )}

              {/* THE MATRIX SCHEDULER SECTION */}
              <div className="margin-top-16">
                <label className="admin-users_detail-label" style={{ fontWeight: '600', marginBottom: '6px' }}>
                  Ma trận phân phối công việc (Bấm vào ô giao lộ để chọn Công nhân - Ao nuôi) 
                  <span style={{ color: '#2563eb', marginLeft: '6px' }}>({form.assignments.length} ô đã chọn)</span>
                </label>
                
                <div style={{ overflowX: 'auto', border: '1px solid #e5e7eb', borderRadius: '8px', maxHeight: '280px' }}>
                  <table className="matrix-table-base">
                    <thead>
                      <tr>
                        <th className="matrix-th-pond" style={{ position: 'sticky', left: 0, background: '#f9fafb', zIndex: 2 }}>
                          Ao phụ trách \ Nhân sự
                        </th>
                        {matrixWorkers.map((w) => (
                          <th key={w.user_id} className="matrix-th-worker">
                            <div className="worker-info-cell">
                              <span style={{ fontWeight: '600' }}>{w.full_name}</span>
                              <span className="worker-usernames-sub">@{w.username}</span>
                            </div>
                          </th>
                        ))}
                      </tr>
                    </thead>
                    <tbody>
                      {matrixPonds.length === 0 ? (
                        <tr>
                          <td colSpan={matrixWorkers.length + 1} style={{ textAlign: 'center', padding: '20px', color: '#64748b' }}>
                            Không tìm thấy ao nuôi nào thỏa mãn trạng thái của loại nghiệp vụ này.
                          </td>
                        </tr>
                      ) : (
                        matrixPonds.map((p) => (
                          <tr key={p.pond_id}>
                            <td className="matrix-th-pond" style={{ position: 'sticky', left: 0, background: '#ffffff', zIndex: 1, fontWeight: '600' }}>
                              {p.pond_name} 
                              <span style={{ display: 'block', fontSize: '11px', fontWeight: 'normal', color: '#64748b' }}>
                                {p.pond_code} — {p.season_id ? `Vụ ID: ${p.season_id}` : 'Không có vụ'}
                              </span>
                            </td>
                            {matrixWorkers.map((w) => {
                              const isChecked = !!form.assignments.find((a) => a.pond_id === p.pond_id && a.worker_id === w.user_id)
                              return (
                                <td
                                  key={`${p.pond_id}-${w.user_id}`}
                                  className={`matrix-cell-intersect ${isChecked ? 'cell-active' : ''}`}
                                  onClick={() => handleCellClick(p.pond_id, w.user_id)}
                                >
                                  {isChecked ? '✓ Đã chọn' : '+'}
                                </td>
                              )
                            })}
                          </tr>
                        ))
                      )}
                    </tbody>
                  </table>
                </div>
              </div>

              {/* TECHNICAL INSTRUCTION DESCRIPTION */}
              <div className="margin-top-16">
                <label className="admin-users_detail-label">Hướng dẫn kỹ thuật / Quy trình thực hiện công việc <span className="text-red">*</span></label>
                <textarea
                  className="form-textarea-base"
                  rows="3"
                  style={{ height: 'auto' }}
                  placeholder="Nhập chi tiết các bước thực hiện nghiệp vụ, lưu ý an toàn kỹ thuật cho công nhân thực địa..."
                  value={form.description}
                  onChange={(e) => setForm({ ...form, description: e.target.value })}
                />
              </div>

              {/* TARGET SCHEDULE TIME PERIOD */}
              <div className="admin-users_detail-grid margin-top-12">
                <div>
                  <label className="admin-users_detail-label">Thời gian bắt đầu <span className="text-red">*</span></label>
                  <input
                    type="datetime-local"
                    className="form-input-date-base"
                    value={form.start_date}
                    onChange={(e) => setForm({ ...form, start_date: e.target.value })}
                  />
                </div>
                <div>
                  <label className="admin-users_detail-label">Hạn chót hoàn thành <span className="text-red">*</span></label>
                  <input
                    type="datetime-local"
                    className="form-input-date-base"
                    value={form.due_date}
                    onChange={(e) => setForm({ ...form, due_date: e.target.value })}
                  />
                </div>
              </div>

            </div>

            {/* BUTTON ACTIONS */}
            <div className="admin-users_modal-buttons admin-users_form-buttons margin-top-24">
              <button type="button" className="btn btn-secondary" onClick={() => setIsCreateOpen(false)}>Hủy bỏ</button>
              <button
                type="button"
                className="btn btn-primary"
                onClick={handleCreateTask}
                disabled={form.assignments.length === 0 || !form.start_date || !form.due_date || loading}
              >
                {loading ? 'Đang kích hoạt...' : `Xác nhận tạo ${form.assignments.length} công việc`}
              </button>
            </div>
          </div>
        </div>
      )}

    </div>
  )
}

export default TechnicianTasks
